#!/usr/bin/env node

const path = require('path');
const {
  buildSupabaseSmtpConfig,
  getOutputDirectory,
  loadConfig,
  writeJson,
  writeText,
} = require('./common.cjs');

async function main() {
  const { config, configPath } = loadConfig();
  const resolved = buildSupabaseSmtpConfig(config);

  const envLocal = [
    '# Generated by packages/auth/infra/email/scripts/01-generate-smtp-config.cjs',
    `EMAIL_SMTP_PROVIDER=${resolved.provider}`,
    `SUPABASE_SMTP_ADMIN_EMAIL=${resolved.payload.smtp_admin_email}`,
    `SUPABASE_SMTP_HOST=${resolved.payload.smtp_host}`,
    `SUPABASE_SMTP_PORT=${resolved.payload.smtp_port}`,
    `SUPABASE_SMTP_USER=${resolved.payload.smtp_user}`,
    `SUPABASE_SMTP_PASS=${resolved.payload.smtp_pass}`,
    `SUPABASE_SMTP_SENDER_NAME=${resolved.payload.smtp_sender_name}`,
    `SUPABASE_SMTP_MAX_FREQUENCY=${resolved.payload.smtp_max_frequency}`,
    '',
  ].join('\n');

  const outputDirectory = getOutputDirectory();
  const envOutputPath = path.join(outputDirectory, 'smtp.env.local');
  const payloadOutputPath = path.join(outputDirectory, 'supabase-auth-config.local.json');

  writeText(envOutputPath, envLocal);
  writeJson(payloadOutputPath, resolved.payload);

  console.log('SMTP config material generated.');
  console.log(`- Config: ${configPath || 'env-only'}`);
  console.log(`- Provider: ${resolved.provider}`);
  console.log(`- SMTP host: ${resolved.payload.smtp_host}:${resolved.payload.smtp_port}`);
  console.log(`- SMTP user configured: ${resolved.payload.smtp_user ? 'yes' : 'no'}`);
  console.log(`- SMTP password configured: ${resolved.payload.smtp_pass ? 'yes' : 'no'}`);
  console.log(`- Output env: ${envOutputPath}`);
  console.log(`- Output payload: ${payloadOutputPath}`);
}

main().catch(error => {
  console.error('SMTP config generation failed.');
  console.error(error instanceof Error ? error.message : String(error));
  process.exit(1);
});
